import{_ as e,c as t,o as a,a9 as r}from"./chunks/framework.UE0CKZYN.js";const f=JSON.parse('{"title":"解压缩工具使用教程","description":"","frontmatter":{},"headers":[],"relativePath":"stage1/soft/ZIP.md","filePath":"stage1/soft/ZIP.md","lastUpdated":1775267150000}'),d={name:"stage1/soft/ZIP.md"},i=r('<h1 id="解压缩工具使用教程" tabindex="-1">解压缩工具使用教程 <a class="header-anchor" href="#解压缩工具使用教程" aria-label="Permalink to &quot;解压缩工具使用教程&quot;">​</a></h1><p>等待补充</p><h2 id="zstd" tabindex="-1">ZSTD <a class="header-anchor" href="#zstd" aria-label="Permalink to &quot;ZSTD&quot;">​</a></h2><p>部分分享者在上传打包时会使用ZSTD算法进行压缩,会导致一些不支持zstd的压缩工具报错</p><p>关于zstd是啥自己去看<a href="https://facebook.github.io/zstd/" target="_blank" rel="noreferrer">zstd主页</a>或者问问ai</p><h3 id="哪些解压缩工具支持zstd" tabindex="-1">哪些解压缩工具支持ZSTD <a class="header-anchor" href="#哪些解压缩工具支持zstd" aria-label="Permalink to &quot;哪些解压缩工具支持ZSTD&quot;">​</a></h3><p>下面列出一些支持zstd的工具</p><ul><li>Windows11内置的解压缩工具,在24H2版本就支持解压zstd了</li><li>bandizip7.x及以后版本 (6.x的主页没写,大家自测吧)</li><li><a href="https://github.com/mcmilk/7-Zip-zstd" target="_blank" rel="noreferrer">7-Zip-zstd</a> 基于7-Zip修改的非官方开源项目</li></ul><p>如果要创建zstd压缩包的话需要使用<a href="https://github.com/mcmilk/7-Zip-zstd" target="_blank" rel="noreferrer">7-Zip-zstd</a>，如果仅需要解压缩的话上面三款都可以.</p><h3 id="winrar" tabindex="-1">WinRAR <a class="header-anchor" href="#winrar" aria-label="Permalink to &quot;WinRAR&quot;">​</a></h3><p>WinRAR我个人觉得还是挺好用的,可惜原生不支持zstd,但是经过测试可以手动移植<a href="https://github.com/mcmilk/7-Zip-zstd" target="_blank" rel="noreferrer">7-Zip-zstd</a>中的dll到WinRAR中从而达成解压缩zstd压缩包的目的，具体操作如下.</p><p>首先到<a href="https://github.com/mcmilk/7-Zip-zstd" target="_blank" rel="noreferrer">7-Zip-zstd</a>项目的Release下载<code>7z25.01-zstd-x64.exe</code>,注意25.01为当前文章发布时最新版本号,下载时以最新版本为准.</p><p>下载完成后无需安装，直接对<code>7z25.01-zstd-x64.exe</code>右键,选择<code>用WinRAR打开</code>将压缩包中的<code>7zxa.dll</code>复制出来备用，打开WinRAR所在目录,将WinRAR目录中的<code>7zxa.dll</code>重命名为<code>7zxa.bak</code>，最后将复制出来的<code>7zxa.dll</code>放入WinRAR目录中即可.</p>',13),o=[i];function s(l,n,c,p,h,_){return a(),t("div",null,o)}const m=e(d,[["render",s]]);export{f as __pageData,m as default};
